const countdown=()=>{const e=new Date("March 1, 2024 00:00:00").getTime()-(new Date).getTime(),n=36e5,t=24*n,o=Math.floor(e/t),r=Math.floor(e%t/n),c=Math.floor(e%n/6e4),u=Math.floor(e%6e4/1e3);document.querySelector(".day").innerText=o,document.querySelector(".hour").innerText=r,document.querySelector(".minute").innerText=c,document.querySelector(".second").innerText=u,e<=0&&(clearInterval(watchCountdown),document.querySelector(".day").innerHTML="0",document.querySelector(".hour").innerHTML="0",document.querySelector(".minute").innerHTML="0",document.querySelector(".second").innerHTML="0")};let watchCountdown=setInterval(countdown,1e3);